 import sailpoint.api.SailPointContext;
 import sailpoint.object.Identity;
 import org.ascn.utils.QueryUtils;
 
 boolean userStatus = false;
 QueryUtils qu = new QueryUtils();
 
 if(!qu.isIdentityActive(identityName)){
  userStatus = true;
   
 }
 
 return userStatus;

  
  import sailpoint.api.IdentityService;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Application;
  import sailpoint.object.Attributes; 
  import sailpoint.object.AuditEvent;
  import sailpoint.object.Bundle;       
  import sailpoint.object.Custom;
  import sailpoint.object.EntitlementGroup; 
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.IdentityEntitlement;
  import sailpoint.object.Link;
  import sailpoint.object.ProvisioningPlan.AccountRequest;        
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  import java.util.Iterator;

  private ProvisioningPlan.AccountRequest newLeaverAccountRequest(AccountRequest actReq, AccountRequest.Operation operation, String appName, String nativeIdentity) {

    actReq = new AccountRequest();    
    actReq.setApplication(appName);
    actReq.setOperation(operation);
    actReq.setNativeIdentity(nativeIdentity);

    return actReq;

  }

  private ProvisioningPlan.AttributeRequest newLeaverAttributeRequest(AttributeRequest attrReq, ProvisioningPlan.Operation operation, boolean assignment, String key, String value) {

    attrReq = new sailpoint.object.ProvisioningPlan.AttributeRequest();
    attrReq.setOperation(operation);
    attrReq.setAssignment(assignment);
    attrReq.setName(key);
    attrReq.setValue(value);

    return attrReq;

  }

  private void auditLeaver3(String identityName, String appName, String nativeIdentity, String entAttr, String entValue) {

    AuditEvent auditEvent = new AuditEvent();
    auditEvent.setApplication(appName);
    auditEvent.setSource("Leaver+3");
    auditEvent.setAction("Comment");
    auditEvent.setTarget(identityName);
    auditEvent.setAccountName(nativeIdentity);
    auditEvent.setAttributeName(entAttr);
    auditEvent.setAttributeValue(entValue);
    auditEvent.setString1("Object will be included in provisioning plan for removal");
    context.saveObject(auditEvent);
    context.commitTransaction();

  }

  ProvisioningPlan plan = new ProvisioningPlan();

  List acctReqList = new ArrayList();

  Identity identity = context.getObjectByName(Identity.class, identityName);   
  Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-AD-DomainMapping");		

  if (null != identity){	       

    QueryOptions ops = new QueryOptions();
    ops.addFilter(Filter.eq("type", "Active Directory - Direct"));
    List adApps = context.getObjects(Application.class, ops);
    IdentityService identityService = new IdentityService(context);

    List refLinks = identityService.getLinks(identity, adApps, null);
    if(refLinks!=null && !refLinks.isEmpty())
    {
      for(Link adLink: refLinks)
      {
        if(null!=adLink && adLink.isDisabled())
        {
          appName = adLink.getApplicationName();
          accountName = adLink.getNativeIdentity();
          ProvisioningPlan.AccountRequest acctADReq = new ProvisioningPlan.AccountRequest();

          if (custom != null && null != custom.get("DomainOUMapping")) {
            domainMap = custom.get("DomainOUMapping");
            String principalName = adLink.getAttribute("msDS-PrincipalName");
            if(Util.isNotNullOrEmpty(principalName)){
              domainAD = getDomain(principalName);
            }

            if(null != domainMap && !domainMap.isEmpty() && null!=domainAD && null != domainMap.get(domainAD)){ 
              disableDN = domainMap.get(domainAD).get("disableOU");
            }
          }


          if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName)){                    
            if(accountName.contains("OU=")){
              valueCN= accountName.substring(0, accountName.indexOf("OU=")-1);
            }

            List attReqs = new ArrayList();
            if(Util.isNotNullOrEmpty(disableDN)){
              attReqs.add(new AttributeRequest("AC_NewParent", ProvisioningPlan.Operation.Set, disableDN));
            }
            if(Util.isNotNullOrEmpty(valueCN)){
              attReqs.add(new AttributeRequest("AC_NewName", ProvisioningPlan.Operation.Set, valueCN));
            } 
            if(null != attReqs && !attReqs.isEmpty()){       
              acctADReq.setApplication(appName);
              acctADReq.setNativeIdentity(accountName);
              acctADReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
              acctADReq.setAttributeRequests(attReqs); 

              acctReqList.add(acctADReq); 
            }
          }
        }
      }
    }

    QueryOptions ops2 = new QueryOptions();
    ops2.setCloneResults(true);
    ops2.addFilter(Filter.eq("identity.id", identity.getId()));

    Iterator itr = context.search(IdentityEntitlement.class, ops2, "id");

    while (itr.hasNext()) {

      String name = null;
      String value = null;
      Application app = null;
      String appName = null;
      String nativeIdentity = null;
      String identityName = identity.getName();

      IdentityEntitlement identityEnt = context.getObjectById(IdentityEntitlement.class, itr.next()[0]);
      Custom customObj = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");

      if (identityEnt != null && customObj != null && customObj.get("IgnoreTerminationApplications") != null) {

        List appsToIgnore = customObj.get("IgnoreTerminationApplications");

        name = identityEnt.getName();
        value = identityEnt.getValue();
        app = identityEnt.getApplication();

        if (app != null) {

          appName = app.getName();

        } else {

          appName = "IIQ";

        }

        if (!Util.nullSafeContains(appsToIgnore, appName) && !appName.equalsIgnoreCase("ServiceNow")) {

        nativeIdentity = identityEnt.getNativeIdentity();

        if (Util.isNullOrEmpty(nativeIdentity)) {

          nativeIdentity = identityName;

        }


        AccountRequest actReq = null;
        actReq = newLeaverAccountRequest(actReq, AccountRequest.Operation.Modify, appName, nativeIdentity);

        AttributeRequest attrReq = null;
        attrReq = newLeaverAttributeRequest(attrReq, ProvisioningPlan.Operation.Remove, false, name, value);
        auditLeaver3(identityName, appName, nativeIdentity, name, value);

        actReq.add(attrReq);

        acctReqList.add(actReq);


      }

      }

    }

    Util.flushIterator(itr);

    plan.setAccountRequests(acctReqList);
    plan.setIdentity(identity);
    
  }
  return plan;

        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningResult;
        import sailpoint.tools.Util;
        
				Map dataMap = new HashMap();
        Identity identityObject = context.getObjectByName(Identity.class,identityName);
        ProvisioningPlan.AccountRequest acctRoleReq = new ProvisioningPlan.AccountRequest();   
         if(null != identityObject && !identityObject.isInactive()){
            dataMap.put("Day 1 IdentityRequest ID ",day1IdentityRequestId);
            logAudit(acctRoleReq, "User is Active. So Role removal is not performed.",  "Disable", identityName,  new ArrayList(), dataMap, day1IdentityRequestId);
            //comment decache //context.decache(identityObject);
         }   
         else{
          if(project!=null){
            List plans = project.getPlans();
            if(null!=plans) {
              for(ProvisioningPlan plan:plans){
                if(plan!=null && plan.getAccountRequests()!=null){
                  if(plan.getResult() != null && Util.isNotNullOrEmpty(plan.getResult().getStatus())){
                    dataMap.put("provisioningResult",plan.getResult().getStatus());
                  }
                  for(AccountRequest accReq : plan.getAccountRequests()){
                     logAudit(accReq, "Role Removal After Three days",  "Disable", identityName,  new ArrayList(), dataMap, identityRequestId);
        						
                  }             	
                }
              }
            }
          }
        }


